package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrintAndQuote() throws IOException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        StringWriter out = new StringWriter();
        Object object = "test";
        CharSequence value = "value";
        int offset = 0;
        int len = value.length();
        boolean newRecord = true;

        // When
        try {
            csvFormat.getClass().getDeclaredMethod("printAndQuote", Object.class, CharSequence.class, int.class, int.class, Appendable.class, boolean.class)
                    .invoke(csvFormat, object, value, offset, len, out, newRecord);
        } catch (Exception e) {
            e.printStackTrace();
        }

        // Then
        assertEquals("\"value\"", out.toString());
    }
}
